require('dotenv').config();
const { ethers } = require('ethers');

// Validate required environment variables
const REQUIRED_ENV_VARS = ['RPC_URL', 'WALLET_PRIVATE_KEY'];

function validateEnvironment() {
  const missing = REQUIRED_ENV_VARS.filter((v) => !process.env[v]);
  if (missing.length > 0) {
    throw new Error(`Missing required environment variables: ${missing.join(', ')}`);
  }
}

validateEnvironment();

// Provider configuration with timeout and retry
const provider = new ethers.JsonRpcProvider(process.env.RPC_URL, undefined, {
  staticNetwork: true,
  batchMaxCount: 1,
});

// Wallet configuration - private key loaded from environment variable only
function createWallet() {
  const privateKey = process.env.WALLET_PRIVATE_KEY;

  if (!privateKey || privateKey.length < 64) {
    throw new Error('Invalid private key configuration');
  }

  const wallet = new ethers.Wallet(privateKey, provider);

  // Clear the private key from the variable reference
  // (Note: the wallet object retains it internally)
  return wallet;
}

const wallet = createWallet();

// Nonce manager to prevent nonce reuse
class NonceManager {
  constructor(wallet) {
    this.wallet = wallet;
    this.currentNonce = null;
    this.mutex = Promise.resolve();
  }

  async acquireNonce() {
    return new Promise((resolve) => {
      this.mutex = this.mutex.then(async () => {
        const onChainNonce = await this.wallet.getNonce('pending');
        if (this.currentNonce === null || this.currentNonce < onChainNonce) {
          this.currentNonce = onChainNonce;
        }
        const nonce = this.currentNonce;
        this.currentNonce++;
        resolve(nonce);
      });
    });
  }

  resetNonce() {
    this.currentNonce = null;
  }
}

const nonceManager = new NonceManager(wallet);

// Input validation utilities
function validateAddress(address) {
  if (!address || !ethers.isAddress(address)) {
    throw new Error(`Invalid Ethereum address: ${address}`);
  }
  return ethers.getAddress(address); // Returns checksummed address
}

function validateAmount(amount) {
  if (!amount || typeof amount !== 'string') {
    throw new Error('Amount must be a non-empty string');
  }

  const parsed = ethers.parseEther(amount);
  if (parsed <= 0n) {
    throw new Error('Amount must be greater than zero');
  }

  return parsed;
}

function sanitizeData(data) {
  if (!data) return '0x';
  if (typeof data !== 'string' || !/^0x[0-9a-fA-F]*$/.test(data)) {
    throw new Error('Invalid hex data');
  }
  return data;
}

// Gas estimation with safety margin
async function estimateGasWithBuffer(txParams, bufferPercent = 20) {
  try {
    const estimatedGas = await provider.estimateGas(txParams);
    const buffer = (estimatedGas * BigInt(bufferPercent)) / 100n;
    return estimatedGas + buffer;
  } catch (error) {
    throw new Error(`Gas estimation failed: ${error.message}`);
  }
}

// Get current gas price with cap
async function getGasPriceWithCap() {
  const feeData = await provider.getFeeData();

  const maxGasPriceGwei = process.env.MAX_GAS_PRICE_GWEI || '100';
  const maxGasPrice = ethers.parseUnits(maxGasPriceGwei, 'gwei');

  if (feeData.maxFeePerGas && feeData.maxFeePerGas > maxGasPrice) {
    throw new Error(
      `Gas price ${ethers.formatUnits(feeData.maxFeePerGas, 'gwei')} gwei exceeds cap of ${maxGasPriceGwei} gwei`
    );
  }

  return feeData;
}

// Rate limiting
class RateLimiter {
  constructor(maxRequests, windowMs) {
    this.maxRequests = maxRequests;
    this.windowMs = windowMs;
    this.requests = [];
  }

  async checkLimit() {
    const now = Date.now();
    this.requests = this.requests.filter((t) => now - t < this.windowMs);

    if (this.requests.length >= this.maxRequests) {
      throw new Error('Rate limit exceeded. Please try again later.');
    }

    this.requests.push(now);
  }
}

const rateLimiter = new RateLimiter(
  parseInt(process.env.RATE_LIMIT_MAX || '10'),
  parseInt(process.env.RATE_LIMIT_WINDOW_MS || '60000')
);

// Transaction logging (no sensitive data)
function logTransaction(action, txHash, from, to, value) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    action,
    txHash,
    from,
    to,
    value: value ? value.toString() : '0',
  };
  console.log('[TX_LOG]', JSON.stringify(logEntry));
}

/**
 * Send ETH to a recipient address
 * @param {string} toAddress - Recipient address
 * @param {string} amountInEth - Amount in ETH as a string (e.g., "0.1")
 * @returns {object} Transaction receipt
 */
async function sendETH(toAddress, amountInEth) {
  await rateLimiter.checkLimit();

  const to = validateAddress(toAddress);
  const value = validateAmount(amountInEth);

  // Check balance before sending
  const balance = await provider.getBalance(wallet.address);
  if (balance < value) {
    throw new Error(
      `Insufficient balance. Have: ${ethers.formatEther(balance)} ETH, Need: ${amountInEth} ETH`
    );
  }

  const feeData = await getGasPriceWithCap();
  const nonce = await nonceManager.acquireNonce();

  const txParams = {
    to,
    value,
    nonce,
    type: 2, // EIP-1559
    maxFeePerGas: feeData.maxFeePerGas,
    maxPriorityFeePerGas: feeData.maxPriorityFeePerGas,
  };

  // Estimate gas
  const gasLimit = await estimateGasWithBuffer(txParams);
  txParams.gasLimit = gasLimit;

  // Verify total cost doesn't exceed balance
  const totalCost = value + gasLimit * feeData.maxFeePerGas;
  if (balance < totalCost) {
    throw new Error(
      `Insufficient balance for transaction + gas. Have: ${ethers.formatEther(balance)} ETH, Need: ${ethers.formatEther(totalCost)} ETH`
    );
  }

  try {
    const tx = await wallet.sendTransaction(txParams);
    logTransaction('SEND_ETH', tx.hash, wallet.address, to, amountInEth);

    const receipt = await tx.wait(
      parseInt(process.env.CONFIRMATION_BLOCKS || '2')
    );

    if (receipt.status === 0) {
      throw new Error(`Transaction reverted: ${tx.hash}`);
    }

    logTransaction('SEND_ETH_CONFIRMED', tx.hash, wallet.address, to, amountInEth);

    return {
      success: true,
      txHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      effectiveGasPrice: receipt.gasPrice.toString(),
    };
  } catch (error) {
    if (error.code === 'NONCE_EXPIRED' || error.message.includes('nonce')) {
      nonceManager.resetNonce();
    }
    throw error;
  }
}

/**
 * Interact with a smart contract - read (call)
 * @param {string} contractAddress - Contract address
 * @param {Array} abi - Contract ABI
 * @param {string} functionName - Function to call
 * @param {Array} args - Function arguments
 * @returns {any} Function return value
 */
async function contractRead(contractAddress, abi, functionName, args = []) {
  await rateLimiter.checkLimit();

  const address = validateAddress(contractAddress);

  if (!Array.isArray(abi) || abi.length === 0) {
    throw new Error('Invalid ABI provided');
  }

  if (!functionName || typeof functionName !== 'string') {
    throw new Error('Invalid function name');
  }

  const contract = new ethers.Contract(address, abi, provider);

  if (!contract[functionName]) {
    throw new Error(`Function ${functionName} not found in contract ABI`);
  }

  // Verify it's a view/pure function
  const fragment = contract.interface.getFunction(functionName);
  if (fragment.stateMutability !== 'view' && fragment.stateMutability !== 'pure') {
    throw new Error(
      `Function ${functionName} is not a read-only function. Use contractWrite instead.`
    );
  }

  try {
    const result = await contract[functionName](...args);
    return result;
  } catch (error) {
    throw new Error(`Contract read failed for ${functionName}: ${error.message}`);
  }
}

/**
 * Interact with a smart contract - write (send transaction)
 * @param {string} contractAddress - Contract address
 * @param {Array} abi - Contract ABI
 * @param {string} functionName - Function to call
 * @param {Array} args - Function arguments
 * @param {string} valueInEth - ETH value to send (optional, default "0")
 * @returns {object} Transaction receipt
 */
async function contractWrite(
  contractAddress,
  abi,
  functionName,
  args = [],
  valueInEth = '0'
) {
  await rateLimiter.checkLimit();

  const address = validateAddress(contractAddress);

  if (!Array.isArray(abi) || abi.length === 0) {
    throw new Error('Invalid ABI provided');
  }

  if (!functionName || typeof functionName !== 'string') {
    throw new Error('Invalid function name');
  }

  const contract = new ethers.Contract(address, abi, wallet);

  if (!contract[functionName]) {
    throw new Error(`Function ${functionName} not found in contract ABI`);
  }

  const feeData = await getGasPriceWithCap();
  const nonce = await nonceManager.acquireNonce();

  const value = valueInEth !== '0' ? ethers.parseEther(valueInEth) : 0n;

  // Build the transaction to estimate gas
  const txOverrides = {
    nonce,
    type: 2,
    maxFeePerGas: feeData.maxFeePerGas,
    maxPriorityFeePerGas: feeData.maxPriorityFeePerGas,
    value,
  };

  try {
    // Estimate gas via the contract method
    const estimatedGas = await contract[functionName].estimateGas(...args, {
      value,
    });
    const buffer = (estimatedGas * 20n) / 100n;
    txOverrides.gasLimit = estimatedGas + buffer;

    // Check balance
    const balance = await provider.getBalance(wallet.address);
    const totalCost = value + txOverrides.gasLimit * feeData.maxFeePerGas;
    if (balance < totalCost) {
      throw new Error(
        `Insufficient balance. Have: ${ethers.formatEther(balance)} ETH, Need: ~${ethers.formatEther(totalCost)} ETH`
      );
    }

    const tx = await contract[functionName](...args, txOverrides);
    logTransaction(
      `CONTRACT_WRITE:${functionName}`,
      tx.hash,
      wallet.address,
      address,
      valueInEth
    );

    const receipt = await tx.wait(
      parseInt(process.env.CONFIRMATION_BLOCKS || '2')
    );

    if (receipt.status === 0) {
      throw new Error(`Transaction reverted: ${tx.hash}`);
    }

    logTransaction(
      `CONTRACT_WRITE_CONFIRMED:${functionName}`,
      tx.hash,
      wallet.address,
      address,
      valueInEth
    );

    return {
      success: true,
      txHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      effectiveGasPrice: receipt.gasPrice.toString(),
      logs: receipt.logs.map((log) => {
        try {
          return contract.interface.parseLog({
            topics: log.topics,
            data: log.data,
          });
        } catch {
          return null;
        }
      }).filter(Boolean),
    };
  } catch (error) {
    if (error.code === 'NONCE_EXPIRED' || error.message.includes('nonce')) {
      nonceManager.resetNonce();
    }
    throw error;
  }
}

