/**
 * Get transaction status
 * @param {string} txHash - Transaction hash
 * @returns {object} Transaction status
 */
async function getTransactionStatus(txHash) {
  if (!txHash || !/^0x[0-9a-fA-F]{64}$/.test(txHash)) {
    throw new Error('Invalid transaction hash');
  }

  const receipt = await provider.getTransactionReceipt(txHash);

  if (!receipt) {
    const tx = await provider.getTransaction(txHash);
    return {
      status: tx ? 'pending' : 'not_found',
      txHash,
    };
  }

  return {
    status: receipt.status === 1 ? 'confirmed' : 'reverted',
    txHash: receipt.hash,
    blockNumber: receipt.blockNumber,
    gasUsed: receipt.gasUsed.toString(),
    confirmations: await provider.getBlockNumber() - receipt.blockNumber,
  };
}

/**
 * Listen for contract events
 * @param {string} contractAddress - Contract address
 * @param {Array} abi - Contract ABI
 * @param {string} eventName - Event name to listen for
 * @param {Function} callback - Callback function for events
 * @returns {Function} Unsubscribe function
 */
function listenToContractEvent(contractAddress, abi, eventName, callback) {
  const address = validateAddress(contractAddress);

  if (!Array.isArray(abi) || abi.length === 0) {
    throw new Error('Invalid ABI provided');
  }

  if (typeof callback !== 'function') {
    throw new Error('Callback must be a function');
  }

  const contract = new ethers.Contract(address, abi, provider);

  if (!contract.filters[eventName]) {
    throw new Error(`Event ${eventName} not found in contract ABI`);
  }

  const listener = (...args) => {
    try {
      callback(null, args);
    } catch (error) {
      console.error(`Error in event callback for ${eventName}:`, error.message);
    }
  };

  contract.on(eventName, listener);

  console.log(`[EVENT_LISTENER] Subscribed to ${eventName} on ${address}`);

  // Return unsubscribe function
  return () => {
    contract.off(eventName, listener);
    console.log(`[EVENT_LISTENER] Unsubscribed from ${eventName} on ${address}`);
  };
}

// ERC-20 Token helper functions
const ERC20_ABI = [
  'function name() view returns (string)',
  'function symbol() view returns (string)',
  'function decimals() view returns (uint8)',
  'function totalSupply() view returns (uint256)',
  'function balanceOf(address owner) view returns (uint256)',
  'function transfer(address to, uint256 amount) returns (bool)',
  'function approve(address spender, uint256 amount) returns (bool)',
  'function allowance(address owner, address spender) view returns (uint256)',
  'event Transfer(address indexed from, address indexed to, uint256 value)',
  'event Approval(address indexed owner, address indexed spender, uint256 value)',
];

/**
 * Get ERC-20 token balance
 * @param {string} tokenAddress - Token contract address
 * @param {string} ownerAddress - Address to check balance for (optional, defaults to wallet)
 * @returns {object} Token balance information
 */
async function getTokenBalance(tokenAddress, ownerAddress) {
  const token = validateAddress(tokenAddress);
  const owner = ownerAddress
    ? validateAddress(ownerAddress)
    : wallet.address;

  const contract = new ethers.Contract(token, ERC20_ABI, provider);

  const [balance, decimals, symbol] = await Promise.all([
    contract.balanceOf(owner),
    contract.decimals(),
    contract.symbol(),
  ]);

  return {
    tokenAddress: token,
    owner,
    symbol,
    decimals: Number(decimals),
    balanceRaw: balance.toString(),
    balanceFormatted: ethers.formatUnits(balance, decimals),
  };
}

/**
 * Transfer ERC-20 tokens
 * @param {string} tokenAddress - Token contract address
 * @param {string} toAddress - Recipient address
 * @param {string} amount - Amount in token units (e.g., "100.5")
 * @returns {object} Transaction receipt
 */
async function transferToken(tokenAddress, toAddress, amount) {
  const token = validateAddress(tokenAddress);
  const to = validateAddress(toAddress);

  if (!amount || typeof amount !== 'string') {
    throw new Error('Amount must be a non-empty string');
  }

  const contract = new ethers.Contract(token, ERC20_ABI, provider);
  const decimals = await contract.decimals();
  const parsedAmount = ethers.parseUnits(amount, decimals);

  if (parsedAmount <= 0n) {
    throw new Error('Amount must be greater than zero');
  }

  // Check token balance
  const balance = await contract.balanceOf(wallet.address);
  if (balance < parsedAmount) {
    const symbol = await contract.symbol();
    throw new Error(
      `Insufficient ${symbol} balance. Have: ${ethers.formatUnits(balance, decimals)}, Need: ${amount}`
    );
  }

  return contractWrite(token, ERC20_ABI, 'transfer', [to, parsedAmount]);
}

/**
 * Approve ERC-20 token spending
 * @param {string} tokenAddress - Token contract address
 * @param {string} spenderAddress - Spender address
 * @param {string} amount - Amount in token units
 * @returns {object} Transaction receipt
 */
async function approveToken(tokenAddress, spenderAddress, amount) {
  const token = validateAddress(tokenAddress);
  const spender = validateAddress(spenderAddress);

  const contract = new ethers.Contract(token, ERC20_ABI, provider);
  const decimals = await contract.decimals();
  const parsedAmount = ethers.parseUnits(amount, decimals);

  return contractWrite(token, ERC20_ABI, 'approve', [spender, parsedAmount]);
}

// Health check
async function healthCheck() {
  try {
    const [blockNumber, network, balance] = await Promise.all([
      provider.getBlockNumber(),
      provider.getNetwork(),
      provider.getBalance(wallet.address),
    ]);

    return {
      status: 'healthy',
      walletAddress: wallet.address,
      network: {
        name: network.name,
        chainId: Number(network.chainId),
      },
      latestBlock: blockNumber,
      walletBalance: ethers.formatEther(balance),
      timestamp: new Date().toISOString(),
    };
  } catch (error) {
    return {
      status: 'unhealthy',
      error: error.message,
      timestamp: new Date().toISOString(),
    };
  }
}

